import React from 'react';
import { GoogleLogin } from '@react-oauth/google';
import { jwtDecode } from "jwt-decode";
import { useNavigate } from 'react-router-dom';

function Home() {
  const navigate = useNavigate();

  const handleSuccess = (credentialResponse) => {
    const userObject = jwtDecode(credentialResponse.credential);
    localStorage.setItem('user', JSON.stringify(userObject)); // Armazena nome, email e imagem [cite: 10, 11]
    navigate('/cadastro'); 
  };

  return (
    <div style={{ textAlign: 'center', marginTop: '50px' }}>
      <h1>Entrada do Sistema</h1>
      <GoogleLogin onSuccess={handleSuccess} onError={() => console.log('Erro no Login')} />
      <div style={{ marginTop: '20px' }}>
        <button onClick={() => navigate('/dupla')}>Ver Integrantes da Dupla</button>
      </div>
    </div>
  );
}

export default Home;
